import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useInterview } from '../context/InterviewContext';
import { 
  Mic, 
  MicOff, 
  Phone, 
  PhoneOff, 
  Volume2, 
  VolumeX,
  MessageSquare,
  Clock,
  User,
  Bot,
  Play,
  Pause,
  Square
} from 'lucide-react';

interface TranscriptEntry {
  id: string;
  speaker: 'STUDENT' | 'AI_INTERVIEWER';
  message: string;
  timestamp: string;
  confidence?: number;
}

interface InterviewFeedback {
  overall_score: number;
  communication_score: number;
  technical_score: number;
  problem_solving_score: number;
  confidence_score: number;
  strengths: string[];
  areas_for_improvement: string[];
  detailed_feedback: string;
  recommendations: string[];
}

const VoiceInterview: React.FC = () => {
  const { interviewId } = useParams<{ interviewId: string }>();
  const navigate = useNavigate();
  const { state: authState } = useAuth();
  const { state: interviewState, dispatch } = useInterview();

  const [isConnected, setIsConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [interviewStatus, setInterviewStatus] = useState<'connecting' | 'active' | 'paused' | 'completed'>('connecting');
  const [transcript, setTranscript] = useState<TranscriptEntry[]>([]);
  const [feedback, setFeedback] = useState<InterviewFeedback | null>(null);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [showTranscript, setShowTranscript] = useState(true);
  const [showFeedback, setShowFeedback] = useState(false);

  const audioRef = useRef<HTMLAudioElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const websocketRef = useRef<WebSocket | null>(null);
  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const startTimeRef = useRef<number>(Date.now());

  useEffect(() => {
    if (interviewId) {
      initializeInterview();
    }

    return () => {
      cleanup();
    };
  }, [interviewId]);

  useEffect(() => {
    if (interviewStatus === 'active') {
      startTimer();
    } else {
      stopTimer();
    }
  }, [interviewStatus]);

  const initializeInterview = async () => {
    try {
      // Connect to WebSocket for real-time communication
      const wsUrl = `ws://localhost:8000/ws/${interviewId}`;
      websocketRef.current = new WebSocket(wsUrl);

      websocketRef.current.onopen = () => {
        console.log('WebSocket connected');
        setIsConnected(true);
        setInterviewStatus('active');

        // Join interview room
        websocketRef.current?.send(JSON.stringify({
          type: 'join_interview',
          participant_id: authState.user?.id,
          participant_name: `${authState.user?.first_name} ${authState.user?.last_name}`,
          role: 'student'
        }));
      };

      websocketRef.current.onmessage = (event) => {
        const data = JSON.parse(event.data);
        handleWebSocketMessage(data);
      };

      websocketRef.current.onerror = (error) => {
        console.error('WebSocket error:', error);
        setIsConnected(false);
      };

      websocketRef.current.onclose = () => {
        console.log('WebSocket disconnected');
        setIsConnected(false);
      };

    } catch (error) {
      console.error('Error initializing interview:', error);
    }
  };

  const handleWebSocketMessage = (data: any) => {
    switch (data.type) {
      case 'transcript_update':
        setTranscript(prev => [...prev, data.entry]);
        break;
      case 'interview_status':
        setInterviewStatus(data.status);
        break;
      case 'ai_response':
        // Play AI response audio
        if (audioRef.current && data.audio_url) {
          audioRef.current.src = data.audio_url;
          audioRef.current.play();
        }
        break;
      case 'interview_completed':
        setInterviewStatus('completed');
        if (data.feedback) {
          setFeedback(data.feedback);
          setShowFeedback(true);
        }
        break;
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);

      mediaRecorderRef.current.ondataavailable = (event) => {
        if (event.data.size > 0 && websocketRef.current) {
          // Send audio data to server
          websocketRef.current.send(JSON.stringify({
            type: 'audio_data',
            interview_id: interviewId,
            audio_data: event.data
          }));
        }
      };

      mediaRecorderRef.current.start(1000); // Collect data every second
      setIsRecording(true);

    } catch (error) {
      console.error('Error starting recording:', error);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      setIsRecording(false);
    }
  };

  const toggleMute = () => {
    setIsMuted(!isMuted);
    if (audioRef.current) {
      audioRef.current.muted = !isMuted;
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    setInterviewStatus(isPaused ? 'active' : 'paused');

    if (websocketRef.current) {
      websocketRef.current.send(JSON.stringify({
        type: 'interview_status',
        status: isPaused ? 'active' : 'paused'
      }));
    }
  };

  const endInterview = async () => {
    try {
      stopRecording();

      if (websocketRef.current) {
        websocketRef.current.send(JSON.stringify({
          type: 'end_interview'
        }));
      }

      setInterviewStatus('completed');

      // Generate feedback
      const response = await fetch(`/api/interviews/${interviewId}/generate-feedback`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${authState.token}`,
          'Content-Type': 'application/json'
        }
      });

      if (response.ok) {
        const feedbackData = await response.json();
        setFeedback(feedbackData.feedback);
        setShowFeedback(true);
      }

    } catch (error) {
      console.error('Error ending interview:', error);
    }
  };

  const startTimer = () => {
    startTimeRef.current = Date.now() - elapsedTime * 1000;
    timerRef.current = setInterval(() => {
      setElapsedTime(Math.floor((Date.now() - startTimeRef.current) / 1000));
    }, 1000);
  };

  const stopTimer = () => {
    if (timerRef.current) {
      clearInterval(timerRef.current);
      timerRef.current = null;
    }
  };

  const cleanup = () => {
    stopRecording();
    stopTimer();
    if (websocketRef.current) {
      websocketRef.current.close();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const getStatusColor = () => {
    switch (interviewStatus) {
      case 'connecting': return 'text-yellow-600';
      case 'active': return 'text-green-600';
      case 'paused': return 'text-orange-600';
      case 'completed': return 'text-gray-600';
      default: return 'text-gray-600';
    }
  };

  const getStatusText = () => {
    switch (interviewStatus) {
      case 'connecting': return 'Connecting...';
      case 'active': return 'Active';
      case 'paused': return 'Paused';
      case 'completed': return 'Completed';
      default: return 'Unknown';
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="bg-white rounded-lg shadow-sm p-6 mb-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">Voice Interview</h1>
              <p className="text-gray-600">Real-time AI-powered interview session</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex items-center space-x-2">
                <Clock className="w-5 h-5 text-gray-500" />
                <span className="text-lg font-mono">{formatTime(elapsedTime)}</span>
              </div>
              <div className={`flex items-center space-x-2 ${getStatusColor()}`}>
                <div className={`w-3 h-3 rounded-full ${interviewStatus === 'active' ? 'bg-green-500' : 'bg-gray-400'}`}></div>
                <span className="font-medium">{getStatusText()}</span>
              </div>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Main Interview Area */}
          <div className="lg:col-span-2">
            {/* Audio Controls */}
            <div className="bg-white rounded-lg shadow-sm p-6 mb-6">
              <div className="flex items-center justify-center space-x-4">
                <button
                  onClick={isRecording ? stopRecording : startRecording}
                  className={`p-4 rounded-full ${
                    isRecording 
                      ? 'bg-red-500 hover:bg-red-600 text-white' 
                      : 'bg-green-500 hover:bg-green-600 text-white'
                  }`}
                >
                  {isRecording ? <MicOff className="w-6 h-6" /> : <Mic className="w-6 h-6" />}
                </button>

                <button
                  onClick={toggleMute}
                  className={`p-4 rounded-full ${
                    isMuted ? 'bg-gray-500 hover:bg-gray-600' : 'bg-blue-500 hover:bg-blue-600'
                  } text-white`}
                >
                  {isMuted ? <VolumeX className="w-6 h-6" /> : <Volume2 className="w-6 h-6" />}
                </button>

                <button
                  onClick={togglePause}
                  className={`p-4 rounded-full ${
                    isPaused ? 'bg-orange-500 hover:bg-orange-600' : 'bg-yellow-500 hover:bg-yellow-600'
                  } text-white`}
                >
                  {isPaused ? <Play className="w-6 h-6" /> : <Pause className="w-6 h-6" />}
                </button>

                <button
                  onClick={endInterview}
                  className="p-4 rounded-full bg-red-500 hover:bg-red-600 text-white"
                >
                  <Square className="w-6 h-6" />
                </button>
              </div>

              <div className="mt-4 text-center">
                <p className="text-sm text-gray-600">
                  {isRecording ? 'Recording... Speak clearly into your microphone' : 'Click the microphone to start speaking'}
                </p>
              </div>
            </div>

            {/* Transcript */}
            {showTranscript && (
              <div className="bg-white rounded-lg shadow-sm p-6">
                <div className="flex items-center justify-between mb-4">
                  <h3 className="text-lg font-semibold text-gray-900">Live Transcript</h3>
                  <button
                    onClick={() => setShowTranscript(false)}
                    className="text-gray-500 hover:text-gray-700"
                  >
                    Hide
                  </button>
                </div>

                <div className="space-y-4 max-h-96 overflow-y-auto">
                  {transcript.map((entry) => (
                    <div
                      key={entry.id}
                      className={`flex items-start space-x-3 ${
                        entry.speaker === 'STUDENT' ? 'justify-end' : 'justify-start'
                      }`}
                    >
                      {entry.speaker === 'AI_INTERVIEWER' && (
                        <div className="w-8 h-8 bg-blue-500 rounded-full flex items-center justify-center">
                          <Bot className="w-4 h-4 text-white" />
                        </div>
                      )}

                      <div className={`max-w-xs lg:max-w-md p-3 rounded-lg ${
                        entry.speaker === 'STUDENT' 
                          ? 'bg-blue-500 text-white' 
                          : 'bg-gray-100 text-gray-900'
                      }`}>
                        <p className="text-sm">{entry.message}</p>
                        <p className="text-xs opacity-75 mt-1">
                          {new Date(entry.timestamp).toLocaleTimeString()}
                        </p>
                      </div>

                      {entry.speaker === 'STUDENT' && (
                        <div className="w-8 h-8 bg-green-500 rounded-full flex items-center justify-center">
                          <User className="w-4 h-4 text-white" />
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Connection Status */}
            <div className="bg-white rounded-lg shadow-sm p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Connection Status</h3>
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">WebSocket</span>
                  <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`}></div>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">Microphone</span>
                  <div className={`w-3 h-3 rounded-full ${isRecording ? 'bg-green-500' : 'bg-gray-400'}`}></div>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">Audio Output</span>
                  <div className={`w-3 h-3 rounded-full ${!isMuted ? 'bg-green-500' : 'bg-red-500'}`}></div>
                </div>
              </div>
            </div>

            {/* Quick Actions */}
            <div className="bg-white rounded-lg shadow-sm p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Quick Actions</h3>
              <div className="space-y-3">
                <button
                  onClick={() => setShowTranscript(!showTranscript)}
                  className="w-full flex items-center space-x-2 p-3 text-left rounded-lg hover:bg-gray-50"
                >
                  <MessageSquare className="w-5 h-5 text-gray-500" />
                  <span className="text-sm">{showTranscript ? 'Hide' : 'Show'} Transcript</span>
                </button>

                {feedback && (
                  <button
                    onClick={() => setShowFeedback(!showFeedback)}
                    className="w-full flex items-center space-x-2 p-3 text-left rounded-lg hover:bg-gray-50"
                  >
                    <MessageSquare className="w-5 h-5 text-gray-500" />
                    <span className="text-sm">{showFeedback ? 'Hide' : 'Show'} Feedback</span>
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Feedback Modal */}
        {showFeedback && feedback && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-6 z-50">
            <div className="bg-white rounded-lg max-w-2xl w-full max-h-[80vh] overflow-y-auto">
              <div className="p-6">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="text-2xl font-bold text-gray-900">Interview Feedback</h2>
                  <button
                    onClick={() => setShowFeedback(false)}
                    className="text-gray-500 hover:text-gray-700"
                  >
                    ×
                  </button>
                </div>

                <div className="space-y-6">
                  {/* Scores */}
                  <div className="grid grid-cols-2 gap-4">
                    <div className="text-center p-4 bg-blue-50 rounded-lg">
                      <p className="text-sm text-gray-600">Overall Score</p>
                      <p className="text-2xl font-bold text-blue-600">{feedback.overall_score}/100</p>
                    </div>
                    <div className="text-center p-4 bg-green-50 rounded-lg">
                      <p className="text-sm text-gray-600">Communication</p>
                      <p className="text-2xl font-bold text-green-600">{feedback.communication_score}/100</p>
                    </div>
                    <div className="text-center p-4 bg-purple-50 rounded-lg">
                      <p className="text-sm text-gray-600">Technical</p>
                      <p className="text-2xl font-bold text-purple-600">{feedback.technical_score}/100</p>
                    </div>
                    <div className="text-center p-4 bg-orange-50 rounded-lg">
                      <p className="text-sm text-gray-600">Problem Solving</p>
                      <p className="text-2xl font-bold text-orange-600">{feedback.problem_solving_score}/100</p>
                    </div>
                  </div>

                  {/* Strengths */}
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-3">Strengths</h3>
                    <ul className="space-y-2">
                      {feedback.strengths.map((strength, index) => (
                        <li key={index} className="flex items-start space-x-2">
                          <div className="w-2 h-2 bg-green-500 rounded-full mt-2 flex-shrink-0"></div>
                          <span className="text-gray-700">{strength}</span>
                        </li>
                      ))}
                    </ul>
                  </div>

                  {/* Areas for Improvement */}
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-3">Areas for Improvement</h3>
                    <ul className="space-y-2">
                      {feedback.areas_for_improvement.map((area, index) => (
                        <li key={index} className="flex items-start space-x-2">
                          <div className="w-2 h-2 bg-orange-500 rounded-full mt-2 flex-shrink-0"></div>
                          <span className="text-gray-700">{area}</span>
                        </li>
                      ))}
                    </ul>
                  </div>

                  {/* Detailed Feedback */}
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-3">Detailed Feedback</h3>
                    <p className="text-gray-700 leading-relaxed">{feedback.detailed_feedback}</p>
                  </div>

                  {/* Recommendations */}
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-3">Recommendations</h3>
                    <ul className="space-y-2">
                      {feedback.recommendations.map((rec, index) => (
                        <li key={index} className="flex items-start space-x-2">
                          <div className="w-2 h-2 bg-blue-500 rounded-full mt-2 flex-shrink-0"></div>
                          <span className="text-gray-700">{rec}</span>
                        </li>
                      ))}
                    </ul>
                  </div>
                </div>

                <div className="mt-6 flex justify-end space-x-3">
                  <button
                    onClick={() => navigate('/dashboard')}
                    className="px-4 py-2 bg-gray-500 text-white rounded-lg hover:bg-gray-600"
                  >
                    Back to Dashboard
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Hidden audio element for AI responses */}
      <audio ref={audioRef} className="hidden" />
    </div>
  );
};

export default VoiceInterview;
